Chapter 6: layered prediction models.

7 min read
2 hours ago

--

The purpose of this book is to share precise step-by-step instructions for how to solve basic problems in Data Science. Often times in Math and Science not every step is demonstrated, thus leaving one to guess about and/or not understand how to actually solve the problem. To not fully understand how to solve a problem prevents one to create new solutions, and thus participate as a creator of new ideas. A step-by-step Data Science algorithms function book is useful, like an LLM generating code, to explain and demonstrate key Data Science concepts and processes. One knows if they understood the concept if the output of the algorithm is correct, and all steps are accepted and logical. The algorithms below are written in JavaScript, for usage with web development, however they can be rewritten in any programming language.
Layered prediction models are models that have more than one input-output layer, such that patterns can be found in complex data.
[0] 1-layer Binary Classification using Logistic Regression
// This function (which is array multiplication) returns an array of dot products. "The dot product is an algebraic operation that takes two equal-length sequences of numbers (usually coordinate vectors), and returns a single number. [Wikipedia - dot product]"
const dot = (arr0, arr1) => {
try {
arr0.at(0).length;
} catch (err) {
arr0 = [arr0];
}
var arr0_cols = arr0.at(0).length;
var arr1_rows = arr1.length; if (arr0_cols == arr1_rows) {
/*Matrix multiplication*/
var arr0_rows = arr0.length;
var arr1_cols = arr1.at(0).length;
var dot = Array.from({length: arr0_rows}, (v0,i0) => { return Array.from({length: arr1_cols}, (v1,i1) => { return 0; }); });
arr0.map((row,r) => {
for (var c=0; c<arr1_cols; c++) {
/*Select columns.*/
var col = arr1.map((row,irow) => { return row.map((v,i) => { return (c == i) ? v : ""; }).filter((x) => x != ""); });
dot[r][c] = row.map((v,i) => { return v*col.at(i); }).reduce((a,cum) => a+cum, 0);
}
});
return dot;
} else {
return "Array dimensions are not correct for multiplication";
}
}
const add = (arr0, arr1) => {
function reshape(r, c, arrflat) {
var out = [];
for (var i=0; i<r; i++) {
var row = arrflat.slice(i*c, (i*c)+c);
out.push(row);
}
return out;
}
var r = arr0.length;
try { var c = arr0.at(0).length; } catch (err) { var c = 1; }
/*console.log("r,c: ", [r,c]);*/
if (arr0.flat(Infinity).length == arr1.flat(Infinity).length) {
/*Same length array element-wise multiplication.*/
arr1 = arr1.flat(Infinity);
var arrflat = arr0.flat(Infinity).map((v,i) => { return Number(Number(v)+Number(arr1.at(i))); });
var out = reshape(r, c, arrflat);
} else if (arr0.flat(Infinity).length == 1 || arr1.flat(Infinity).length == 1) {
/*Scalar and array multiplication.*/
if (arr0.flat(Infinity).length == 1) { var scalar = arr0.flat(Infinity); var arr = arr1.flat(Infinity); } else { var scalar = arr1.flat(Infinity); var arr = arr0.flat(Infinity); }
var arrflat = arr.map((v,i) => { return Number(Number(v)+Number(scalar)); });
var out = reshape(r, c, arrflat);
} else {
var out = "Arrays can not be added; both arrays must be the same size, or one array must be a scalar.";
}
return out;
}
function standardization(x) {
var avg = x.reduce((a,c) => a+c, 0)/x.length;
var standard_deviation = Math.pow(x.map((v,i) => { return Math.pow(v-avg, 2); }).reduce((a,c) => a+c, 0)/x.length, 0.5);
return x.map((v,i) => { return (v - avg)/standard_deviation; });
}
function sigmoid(arr) {
return arr.map((v,i) => { return [1/(1 + Math.exp(-v))]; });
}
function predict_logistic(X, w, b) {
var y_hat = add(dot(X, w), b);
// console.log("y_hat before scaling: ", y_hat);
// Normalize: make values maximally spread-out from [0, 1], so that sigmoid can be bounded from [0.5, 1].
// var minimum = Math.min(...y_hat.flat(Infinity));
// y_hat = y_hat.map((v,i) => { return v-minimum; });
// var maximum = Math.max(...y_hat.flat(Infinity));
// y_hat = y_hat.map((v,i) => { return v/maximum; });
// console.log("y_hat after scaling: ", y_hat);
// OR
// Standardize: make values maximally spread-out from [-1, 1], so that sigmoid can be bounded from [0, 1].
y_hat = standardization(y_hat.flat(Infinity));
// console.log("y_hat standardization: ", y_hat);
var arr = y_hat.flat(Infinity).map((v,i) => { return Math.abs(v); });
var maximum = Math.max(...arr);
y_hat = y_hat.map((v,i) => { return v/maximum; });
// console.log("y_hat after scaling: ", y_hat);
var y_hat_sigmoid = sigmoid(y_hat);
// console.log("y_hat_sigmoid: ", y_hat_sigmoid);
return y_hat_sigmoid;
}
function log_baseNum(scalar, base_number) {
return Math.log10(scalar)/Math.log10(base_number);
}
function partial_derivative_logistic(X, y_p, y) {
var r = X.length;
var c = X.at(0).length;
var y_p = y_p.flat(Infinity); // size [r,1]
var y = y.flat(Infinity); // size [r,1]
// dJ(w,b)/db = -1/N sum_{i=1}^{N} [ln(y_p_i) + (1-ln(y_p_i))]
var sum_dj_db = 0;
for (var i=0; i<r; i++) {
var ln_y_p_i = log_baseNum(y_p.at(i), 2.71828);
var sum_dj_db = sum_dj_db + ln_y_p_i + (1-ln_y_p_i);
}
// dJ(w,b)/dw = -1/N sum_{i=1}^{N} [(y_i/y_p_i) - ((1-y_i)/(1-y_p_i))]
var sum_dj_dw = 0;
for (var i=0; i<r; i++) {
var value = (y.at(i)/y_p.at(i)) - ( (1-y.at(i)) / (1-y_p.at(i)) );
var sum_dj_dw = sum_dj_dw + value;
}
var dj_dw = -(1/r) * sum_dj_dw;
var dj_db = -(1/r) * sum_dj_db;
return [dj_dw, dj_db];
}
function loss_logistic_regression(y, y_p) {
var small_floating_point_number = 1/(10**Math.floor(6+Math.random()*20));
// console.log("small_floating_point_number: ", small_floating_point_number);
return -(1/y.length)* y.map((v,i) => {
// Prevent NaN.
if (y_p.at(i) == 0) {
var y_p0 = y_p.at(i) + small_floating_point_number; // Add a really small number to zero, so log(almost zero) will not give -Infinity.
} else {
var y_p0 = y_p.at(i);
}
if ((1-y_p.at(i)) == 0) {
var y_p1 = (1 - y_p.at(i)) + small_floating_point_number; // Add a really small number to zero.
} else {
var y_p1 = (1 - y_p.at(i));
}
return v*log_baseNum(y_p0, 2.71828) + (1-v)*log_baseNum(y_p1, 2.71828); }).reduce((a,c) => a+c, 0);
}
function gradient_descent(X, y, lr, iterations) {
var r = X.length;
var c = X.at(0).length;
var w = Array.from({length:c}, (v,i) => { return [Math.random()]; });
var b = Array.from({length:r}, (v,i) => { return [Math.random()]; });
var y_p = predict_logistic(X, w, b);
// console.log("y_p: ", y_p);
[dj_dw, dj_db] = partial_derivative_logistic(X, y_p, y);
// console.log("dj_dw: ", dj_dw);
// console.log("dj_db: ", dj_db);
var J = [loss_logistic_regression(y, y_p)];
// console.log("J: ", J);
for (var i=0; i<iterations; i++) {
w = w.map((v,i) => { return [v-(dj_dw*lr)]; });
b = b.map((v,i) => { return [v-(dj_db*lr)]; });
// OR
// b = Array.from({length:r}, (v,i) => { return [0]; });
y_p = predict_logistic(X, w, b);
[dj_dw, dj_db] = partial_derivative_logistic(X, y_p, y);
// console.log("dj_dw: ", dj_dw);
// console.log("dj_db: ", dj_db);
J.push(loss_logistic_regression(y, y_p));
}
return [y_p, J, w, b];
}
function accuracy(y, y_p) {
var y_p = y_p.flat(Infinity); // size [r,1]
var y = y.flat(Infinity); // size [r,1]
var TP = 0;
var FP = 0;
var TN = 0;
var FN = 0;
for (var i=0; i<y.length; i++) {
if (y.at(i)==1 && y_p.at(i)==1) {
TP = TP + 1;
}
if (y.at(i)==0 && y_p.at(i)==1) {
FP = FP + 1;
}
if (y.at(i)==0 && y_p.at(i)==0) {
TN = TN + 1;
}
if (y.at(i)==1 && y_p.at(i)==0) {
FN = FN + 1;
}
}
return (TP+TN)/(TP+FP+TN+FN);
}
// Create categorical data.
var r = 30;
var c = 2;
var X = Array.from({length:r}, (v0,i0) => {
if (i0 < parseInt(r/2)) {
return Array.from({length:c}, (v1,i1) => { if (i1 == 0) { return Math.random() + 2; } else { return Math.random() + 1; }; });
} else {
return Array.from({length:c}, (v1,i1) => { if (i1 == 0) { return Math.random() + 10; } else { return Math.random() + 5; }; });
}
});
var y = Array.from({length:r}, (v,i) => {
if (i < parseInt(r/2)) {
return 0;
} else {
return 1;
}
});
console.log("X: ", X);
console.log("y: ", y);
var [y_p, J, w, b] = gradient_descent(X, y, 0.1, 10);
console.log("y_p decimal: ", y_p);
console.log("J: ", J);
console.log("w: ", w);
console.log("b: ", b);
// Make sigmoid output a binary integer.
y_p = y_p.map((v,i) => { return (v > 0.5) ? 1 : 0; });
console.log("y_p binary integer: ", y_p);
var accuracy0 = accuracy(y, y_p);
console.log("accuracy0: ", accuracy0);
